widgets.onValue:
if(get("toggle_panel_lights")==0){
  set('color_settings_lights','rgb(' + get("R1") + ',' + get("G1") + ',' + get("B1") + ',' + get("A1") + ')')
  set('lights',get("betalights"))
  set('lights_fader_interaction',"true")
  set('toggle_panel_lights',1)
} else if(get("toggle_panel_lights")==1){
  set('color_settings_lights',"rgb(255,255,255,0.25")
  set('lights',1024)
  set('lights_fader_interaction',"false")
  set('toggle_panel_lights',0)
}

if(get("toggle_lights_color")==0){
  set('lights_color','rgb(' + get("R2") + ',' + get("G2") + ',' + get("B2") + ',' + get("A2") + ')')
  set('toggle_lights_color',1)
} else if(get("toggle_lights_color")==1){
  set('lights_color','#ffffff')
  set('toggle_lights_color',2)
} else if(get("toggle_lights_color")==2){
  set('lights_color','rgb(' + get("R1") + ',' + get("G1") + ',' + get("B1") + ',' + get("A1") + ')')
  set('toggle_lights_color',0)
}

if(get("toggle_panel_claps")==0){
  set('color_settings_claps','rgb(' + get("R1") + ',' + get("G1") + ',' + get("B1") + ',' + get("A1") + ')')
  set('lights',get("betaclaps"))
  set('claps_fader_interaction',"true")
  set('toggle_panel_claps',1)
} else if(get("toggle_panel_claps")==1){
  set('color_settings_claps',"rgb(255,255,255,0.25")
  set('claps',1024)
  set('claps_fader_interaction',"false")
  set('toggle_panel_claps',0)
}

if(get("toggle_claps_color")==0){
  set('claps_color','rgb(' + get("R2") + ',' + get("G2") + ',' + get("B2") + ',' + get("A2") + ')')
