} else if(get("toggle_claps_color")==1){
  set('claps_color','#ffffff')
  set('toggle_claps_color',2)
} else if(get("toggle_claps_color")==2){
  set('claps_color','rgb(' + get("R1") + ',' + get("G1") + ',' + get("B1") + ',' + get("A1") + ')')
  set('toggle_claps_color',0)
}

if(get("mode")==0){
  set('OP_fader',0)
  set('OP_circles',1)
  set('OP_8circles',0)
  set('mode',1)
} else if(get("mode")==1){
  set('OP_fader',0)
  set('OP_circles',0)
  set('OP_8circles',1)
  set('mode',2)
} else if(get("mode")==2){
  set('OP_fader',1)
  set('OP_circles',0)
  set('OP_8circles',0)
  set('mode',0)
}

